/* 重置默认边距 */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

.page-wrapper {
  width: 100%;
  min-height: 100vh;
  background-color: #ffffff;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  height: 100vh;
  max-width: 375px;
  margin: 0 auto;
}

/* 导航栏 */
.nav-bar {
  width: 100%;
  flex-shrink: 0;
}

.nav-image {
  width: 100%;
  height: auto;
  display: block;
}

/* 主要内容区域 */
.main-content {
  flex: 1;
  padding: 0 20px;
  display: flex;
  flex-direction: column;
  gap: 24px;
  margin-top: 20px;
  overflow-y: auto;
}

/* Banner 广告图 */
.banner-wrapper {
  width: 100%;
  height: 112px;
  border-radius: 10px;
  overflow: hidden;
  flex-shrink: 0;
}

.banner-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* 服务内容区域 */
.service-section {
  display: flex;
  flex-direction: column;
  gap: 14px;
}

/* 标题区 */
.title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
}

.service-title {
  font-size: 20px;
  font-weight: 500;
  color: #4d4d4d;
  font-family: "PingFang SC", sans-serif;
}

.teacher-info {
  display: flex;
  align-items: center;
  gap: 4px;
}

.teacher-label {
  font-size: 14px;
  color: #666666;
  font-family: "PingFang SC", sans-serif;
}

.teacher-avatar {
  width: 24px;
  height: 24px;
  border-radius: 9px;
  background-color: #fcda00;
  display: block;
}

/* 功能入口列表 */
.feature-list {
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.feature-card {
  width: 100%;
  height: 64px;
  background-color: #fff3eb;
  border-radius: 18px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 20px;
}

.feature-left {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
  min-width: 0;
}

.feature-icon {
  width: 36px;
  height: 36px;
  border-radius: 10.5px;
  flex-shrink: 0;
  display: block;
}

.feature-name {
  font-size: 16px;
  font-weight: 500;
  color: #6b2d03;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-family: "PingFang SC", sans-serif;
}

.feature-right {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
  margin-left: 8px;
}

.feature-status {
  font-size: 14px;
  color: #e35b00;
  white-space: nowrap;
  font-family: "PingFang SC", sans-serif;
}

.chevron-icon {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

.chevron-gray {
  color: #e0dfdf;
}

/* 底部链接 */
.bottom-link {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  margin-top: 10px;
}

.bottom-link-text {
  font-size: 14px;
  color: #b2b2b2;
  font-family: "PingFang SC", sans-serif;
}

/* 底部指示条 */
.bottom-indicator {
  width: 100%;
  height: 34px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.indicator-bar {
  width: 134px;
  height: 5px;
  background-color: #000000;
  border-radius: 9999px;
}

